// Scans modules/<slug>/module.ts and writes modules/registry.generated.ts.
// Runs automatically on `predev` / `prebuild`. The generated file is git-ignored,
// so adding a module NEVER produces a shared-file diff. Do not run/edit by hand.

import { readdirSync, statSync, existsSync, writeFileSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const modulesDir = join(here, "..", "modules");

const slugs = readdirSync(modulesDir)
  .filter((name) => {
    if (name.startsWith("_") || name.startsWith(".")) return false; // _template, dotfiles
    const dir = join(modulesDir, name);
    if (!statSync(dir).isDirectory()) return false;
    return existsSync(join(dir, "module.ts")) || existsSync(join(dir, "module.tsx"));
  })
  .sort();

const imports = slugs.map((s, i) => `import m${i} from "@/modules/${s}/module";`).join("\n");
const list = slugs.map((_, i) => `m${i}`).join(", ");

const out = `// AUTO-GENERATED by scripts/gen-registry.mjs — do not edit, do not commit.
import type { ModuleDefinition } from "@/lib/define-module";
${imports}

export const generatedModules: ModuleDefinition[] = [${list}];
`;

writeFileSync(join(modulesDir, "registry.generated.ts"), out);
console.log(`gen-registry: ${slugs.length} module(s)${slugs.length ? " → " + slugs.join(", ") : ""}`);
